[346] يُنظر: ((تفسير ابن جرير)) (20/180)، ((الهداية)) لمكي (10/6313)، ((تفسير ابن عاشور)) (23/359). قال الشَّوكاني: (هذا الأمرُ للتَّهديدِ والتَّقريعِ والتَّوبيخِ، كقَولِه تعالى: اعْمَلُوا مَا شِئْتُمْ
[فصلت: 40]
). ((تفسير الشوكاني)) (4/522، 523). ويُنظر: ((تفسير ابن عطية)) (4/524). وممَّن قال بأنَّ الأمرَ هنا للتَّهديدِ: ابنُ عطية، وابنُ كثير، والبِقاعي. يُنظر: ((تفسير ابن عطية)) (4/524)، ((تفسير ابن كثير)) (7/90)، ((نظم الدرر)) للبقاعي (16/475). قال ابنُ عثيمين: (هذا يحتمِلُ أن يكونَ تَهديدًا، ويحتمِلُ أن يكونَ تَحدِّيًا... والقاعِدةُ عندَنا في التَّفسيرِ: أنَّه إذا كانت الآيةُ تَحمِلُ مَعنيَينِ لا يَتنافَيانِ تُحمَلُ عليهما جميعًا). ((تفسير ابن عثيمين- سورة الزمر)) (ص: 133).

[499] يُنظر: ((تفسير ابن جرير)) (20/189)، ((تفسير ابن عطية)) (4/527)، ((تفسير ابن كثير)) (7/93)، ((تفسير السعدي)) (ص: 722)، ((تفسير ابن عاشور)) (23/378). قيل: إنَّ ما ذُكِرَ تَذكيرٌ وتَنبيهٌ على أنَّه لا بُدَّ مِن صانعٍ حَكيمٍ، وأنَّ ذلك كائِنٌ عن تقديرٍ وتَدبيرٍ، لا عن تَعطيلٍ وإهمالٍ. قاله الزمخشري. يُنظر: ((تفسير الزمخشري)) (4/122). وقيل: إنَّه مَثَلٌ للدُّنيا؛ فالدُّنيا هكذا، تكونُ خَضِرةً نَضِرةً حَسناءَ، ثمَّ تعودُ عَجوزًا شَوهاءَ، والشَّابُّ يعودُ شَيخًا هَرِمًا كبيرًا ضَعيفًا، وبعدَ ذلك كُلِّه الموتُ. قال ابنُ كثير: (وكثيرًا ما يَضرِبُ اللهُ تعالى مَثَلَ الحياةِ الدُّنيا بما يُنزِلُ اللهُ مِن السَّماءِ مِن ماءٍ، ويُنبِتُ به زُروعًا وثمارًا، ثمَّ يكونُ بعدَ ذلك حُطامًا، كما قال تعالى: وَاضْرِبْ لَهُمْ مَثَلَ الْحَيَاةِ الدُّنْيَا كَمَاءٍ أَنْزَلْنَاهُ مِنَ السَّمَاءِ فَاخْتَلَطَ بِهِ نَبَاتُ الْأَرْضِ فَأَصْبَحَ هَشِيمًا تَذْرُوهُ الرِّيَاحُ وَكَانَ اللَّهُ عَلَى كُلِّ شَيْءٍ مُقْتَدِرًا
[الكهف: 45]
). ((تفسير ابن كثير)) (7/93). ويُنظر: ((تفسير الشوكاني)) (4/525). وقيل: إنَّها ذِكرى للبَعثِ مِن القُبورِ وإحياءِ الموتى. يُنظر: ((تفسير ابن جرير)) (20/189)، ((تفسير ابن عطية)) (4/527). وقيل: يَذْكُرونَ به عنايةَ رَبِّهم ورَحمتَه بعِبادِه؛ حيث يَسَّرَ لهم هذا الماءَ، وخَزَنَه بخزائِنِ الأرضِ تبَعًا لِمَصالحِهم، ويَذكُرونَ به كَمالَ قُدرتِه، وأنَّه يُحيي الموتى، كما أحيا الأرضَ بعدَ مَوتِها، ويَذكُرونَ به أنَّ الفاعِلَ لذلك هو المُستَحِقُّ للعِبادةِ. قاله السعدي. يُنظر: ((تفسير السعدي)) (ص: 722). ويُنظر أيضًا: ((تفسير ابن عاشور)) (23/378، 379)، ((تفسير ابن عثيمين- سورة الزمر)) (ص: 171).

[1262] يُنظر: ((تفسير مقاتل بن سليمان)) (3/685)، ((تفسير ابن جرير)) (20/245)، ((تفسير السعدي)) (ص: 729)، ((تفسير ابن عثيمين- سورة الزمر)) (ص: 450-452). قال ابنُ تَيميَّةَ: (لم يَكُنِ العَرشُ داخلًا فيما يُقبَضُ ويُطوَى ويُبدَّلُ ويُغيَّرُ، كما قال في الآيةِ: وَحُمِلَتِ الْأَرْضُ وَالْجِبَالُ فَدُكَّتَا دَكَّةً وَاحِدَةً * فَيَوْمَئِذٍ وَقَعَتِ الْوَاقِعَةُ * وَانْشَقَّتِ السَّمَاءُ فَهِيَ يَوْمَئِذٍ وَاهِيَةٌ * وَالْمَلَكُ عَلَى أَرْجَائِهَا وَيَحْمِلُ عَرْشَ رَبِّكَ فَوْقَهُمْ يَوْمَئِذٍ ثَمَانِيَةٌ
[الحاقة: 14 - 17]
). ((بيان تلبيس الجهمية)) (1/469).

[1264] أخرجه الترمذي (3241) واللفظ له، والنَّسائي في ((السنن الكبرى)) (11453)، وأحمد (24856). قال الترمذي: (حسَنٌ صحيحٌ غريبٌ من هذا الوجه). وصحَّح إسنادَه الحاكمُ في ((المستدرك)) (3630)، وصحَّح الحديثَ ابنُ الملقِّن في ((شرح البخاري)) (19/178)، والألباني في ((صحيح سنن الترمذي)) (3241)، وصحَّح إسناده شعيبٌ الأرناؤوط في تخريج ((مسند أحمد)) (24856). وأخرجه من طريقٍ آخَرَ وبلفظٍ مُقاربٍ: التِّرمذيُّ (3242) عن عائشةَ رَضِيَ الله عنها أنَّها قالت: ((يا رَسولَ اللهِ وَالْأَرْضُ جَمِيعًا قَبْضَتُهُ يَوْمَ الْقِيَامَةِ وَالسَّماوَاتُ مَطْوِيَّاتٌ بِيَمِينِهِ، فأين المؤمِنونَ يومَئذٍ؟! قال: على الصِّراطِ يا
عائِشةُ
)). قال الترمذيُّ: (حسنٌ صحيحٌ). وصحَّحه ابنُ العربي في ((عارضة الأحوذي)) (6/314)، والألباني في ((صحيح سنن الترمذي)) (3242).
